import {OjDialogBase} from "./OjDialogBase";
import { SlotProxy, slotProxy } from "../../";
import { WebElement } from "selenium-webdriver";

/**
 * This is the component WebElement for oj-dialog. Retrieve an instance of the class
 * using its convenience function:
 * ```javascript
 * await ojDialog(driver, By.css('oj-dialog'))
 * ```
 */
export class OjDialog extends OjDialogBase {
  /**
   * Dismiss the dialog
   */
  async doClose() {
    await this.whenReady();
    await this.getDriver().executeScript('arguments[0].close()', this)
    await this.whenBusyContextReady();
  }
}
